"""
Christ Layer — 2 Chronicles chapters 6–8
Run: python3 scripts/zc-christ-2chronicles-6-8.py

Key christological content:
- Ch 6: Solomon's temple dedication prayer — type of Christ as the true temple, true mediator,
  and true answer to every intercession; foreigner inclusion shadows Gentile mission
- Ch 7: YHWH's response — fire from heaven shadows Pentecost; divine glory excludes then
  welcomes; 7:14 fulfilled in Christ who meets every condition on behalf of his people;
  conditional covenant fulfilled in Christ's perfect obedience; desolated temple shadows Cross
- Ch 8: Kingdom administration after completion — Israel as officers shadows priestly kingdom;
  festival calendar fulfilled in Christ; nations' wealth shadows eschatological ingathering
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRON2_CHRIST_6_8 = {
  "6": {
    "1": "<p><em>Shadow / Theme.</em> Solomon declares that YHWH said he would dwell in thick darkness (<em>ʿārāpel</em>) — the cloud that marked the divine presence at Sinai (Exod 20:21) and the crossing of the sea (Exod 14:20). The thick-darkness theology says the fullness of God cannot be directly seen: he dwells hidden in cloud and fire. Christ is the end of the thick darkness — &ldquo;the light has come into the world&rdquo; (John 3:19) and &ldquo;God who said let light shine out of darkness has shone in our hearts in the face of Jesus Christ&rdquo; (2 Cor 4:6). The incarnation replaces cloud with a human face. The darkness that concealed the deity is parted by the one who is &ldquo;the radiance of the glory of God and the exact imprint of his nature&rdquo; (Heb 1:3).</p>",
    "2": "<p><em>Type.</em> Solomon declares: &ldquo;I have built you an exalted house, a place for you to dwell forever.&rdquo; The forever-claim of the Solomonic temple is provisional — it was destroyed within four centuries. Christ replaces the stone temple with an indestructible one: &ldquo;Destroy this temple and in three days I will raise it up&rdquo; (John 2:19-21). His resurrected body is the permanent dwelling of the divine fullness (Col 2:9), and the church built on him is the &ldquo;holy temple in the Lord&rdquo; that grows into a dwelling place for God (Eph 2:21-22). The forever-dwelling is not a building but a person and a people.</p>",
    "3": "<p><em>Theme.</em> Solomon turns and blesses the entire assembly — the king-priest who stands between God and people, pronouncing blessing from the sacred precincts outward. The Aaronic blessing (Num 6:24-26) was a priestly act; here the Davidic king performs a priestly function. Christ is the true king-priest (Heb 7:1-3, Melchizedek typology) whose blessing encompasses all his people. His final act before the ascension was to lift his hands and bless his disciples (Luke 24:50-51) — the royal-priestly blessing in permanent, unrepeated form.</p>",
    "4": "<p><em>Theme.</em> &ldquo;Blessed be YHWH the God of Israel, who with his hand has fulfilled what he spoke with his mouth to my father David.&rdquo; The fulfillment formula — divine promise kept. Solomon sees himself as the fulfillment of the Davidic covenant (2 Sam 7:12-16), and in the near term he is. But the NT identifies Christ as the ultimate and complete fulfillment: &ldquo;we bring you the good news that what God promised to the fathers, this he has fulfilled to us their children by raising Jesus&rdquo; (Acts 13:32-33). Every fulfilled-word formula in Chronicles finds its deepest referent in Christ&rsquo;s resurrection as the yes to all of God&rsquo;s promises (2 Cor 1:20).</p>",
    "5": "<p><em>Theme.</em> &ldquo;Since the day I brought my people out of Egypt, I chose no city in all the tribes of Israel to build a house in.&rdquo; Centuries of preparation — no permanent dwelling for YHWH in Israel from the Exodus until David. This long waiting period shadows the &ldquo;fullness of time when God sent forth his Son&rdquo; (Gal 4:4). The specific timing of God&rsquo;s choice (no city chosen until the Davidic moment) teaches that the incarnation was not improvised but prepared across generations.</p>",
    "6": "<p><em>Type.</em> YHWH chose Jerusalem and chose David — the double election of city and king converging in one divine purpose. In the NT, election is always &ldquo;in Christ&rdquo; (Eph 1:4) — the city and the Davidic heir are embodied in Christ who is both the true Jerusalem (&ldquo;the heavenly Jerusalem&rdquo; and its king, Heb 12:22; Rev 21:22-23) and the chosen Davidic Son. All divine election passes through him.</p>",
    "7": "<p><em>Type.</em> David wanted to build a house for the name of YHWH — the unfulfilled desire of the man after God&rsquo;s own heart. David represents the entirety of OT longing and preparation: those who desire God&rsquo;s dwelling but cannot achieve it. Christ alone accomplishes what all the OT longed for — the permanent divine-human dwelling — because he is both the builder and the building, the priest and the temple (John 2:19-21; Heb 3:3-6).</p>",
    "8": "<p><em>Theme.</em> &ldquo;You did well that it was in your heart&rdquo; — the divine commendation of intent even when the act is impossible. Christ does not merely commend the heart-intention but fulfills it: he is the one who carries all of Israel&rsquo;s unfulfilled desires to completion. Where every previous servant fell short of the fullness of their God-given intent, Christ does &ldquo;far more abundantly than all we ask or think&rdquo; (Eph 3:20).</p>",
    "9": "<p><em>Type.</em> David was disqualified from building because he was &ldquo;a man of war and shed blood.&rdquo; The true temple builder must be the Prince of Peace (Isa 9:6). Christ is the one who ended the primordial warfare between God and humanity — not by avoiding conflict but by absorbing it at the cross, achieving the peace &ldquo;through the blood of his cross&rdquo; (Col 1:20). He is the builder of the eternal temple precisely because he is the Peace (Eph 2:14) that replaces war.</p>",
    "10": "<p><em>Direct.</em> &ldquo;YHWH has fulfilled his promise that he made... I have risen in the place of David my father, and sit on the throne of Israel.&rdquo; The throne promise of 2 Sam 7:12-16. Acts 2:30-31 applies this fulfillment directly to Christ: David &ldquo;foresaw and spoke about the resurrection of the Christ, that he was not abandoned to Hades.&rdquo; Solomon is the near-term fulfillment; Christ is the final, permanent fulfillment — the Son who sits on the throne forever (Heb 1:8, &ldquo;your throne, O God, is forever and ever&rdquo;).</p>",
    "11": "<p><em>Shadow.</em> The ark of the covenant placed in the Most Holy Place — the throne of the divine presence, accessible only once a year and only to the high priest under threat of death (Lev 16:2). Christ is the <em>hilast&emacr;rion</em> (mercy seat, Rom 3:25) — the true ark-cover where divine justice and covenant love meet in his blood. Through him, believers enter the Most Holy Place &ldquo;with confidence&rdquo; at any time (Heb 10:19-22) — the veil that enforced exclusion has been torn (Matt 27:51).</p>",
    "12": "<p><em>Type.</em> Solomon stands before the altar — the mediatorial position between the people and the divine fire. He is both king (sovereign authority) and intercessor (advocate before God). Christ is the one mediator who unites both roles inseparably (1 Tim 2:5; Heb 7:24-25). The altar before which Solomon stands is the shadow; the cross is the reality — the place where the true mediator made the perfect offering that his intercession cost him.</p>",
    "13": "<p><em>Type.</em> Solomon kneels and spreads his hands toward heaven. The spread hands evoke both prayer and the cruciform posture — Christ&rsquo;s arms spread on the cross are the ultimate intercessory posture. He who intercedes for us from heaven (Rom 8:34; Heb 7:25) first interceded on the cross by absorbing what our sin deserved, then asked the Father to forgive those who crucified him (Luke 23:34) — intercession in its most costly form.</p>",
    "14": "<p><em>Theme.</em> &ldquo;O YHWH God of Israel, there is no God like you in heaven or on earth.&rdquo; The incomparability formula reaches its apex in Christ: &ldquo;No one has ever seen God; the only-begotten Son, who is in the bosom of the Father, he has made him known&rdquo; (John 1:18). The incomparable God that Solomon addresses is most fully revealed in Christ, who is &ldquo;the image of the invisible God&rdquo; (Col 1:15) and &ldquo;the exact imprint of his nature&rdquo; (Heb 1:3). To see Christ is to see the incomparable God.</p>",
    "15": "<p><em>Theme.</em> &ldquo;You have kept with your servant David my father what you promised him.&rdquo; The covenant-faithfulness across time theme. All of God&rsquo;s promises find their permanent &ldquo;yes&rdquo; in Christ (2 Cor 1:20): not a sequence of partial fulfillments that might yet fail, but a single decisive Yes enacted in the incarnation, death, and resurrection. Christ is not only the latest in a series of promise-fulfillments but the final ground that secures all previous and subsequent ones.</p>",
    "16": "<p><em>Direct.</em> &ldquo;You shall not lack a man to sit before me on the throne of Israel&rdquo; — the perpetual-heir promise. Peter cites this directly in Acts 2:30-31 as fulfilled in the resurrection of Christ: David &ldquo;was a prophet and knew that God had sworn with an oath to him that he would set one of his descendants on his throne; he foresaw and spoke about the resurrection of the Christ.&rdquo; The resurrection guarantees that the Davidic throne is permanently and indestructibly occupied.</p>",
    "17": "<p><em>Theme.</em> &ldquo;Now therefore, O YHWH God of Israel, let your word be confirmed which you have spoken to your servant David.&rdquo; The prayer that divine promise be kept. Christ is the divine Word who himself confirms the promise by being the fulfillment — not a future event that God might or might not perform, but the incarnate Son who is simultaneously the promiser and the promised one, the one who speaks the word and the one who is the Word (John 1:1-14).</p>",
    "18": "<p><em>Type.</em> &ldquo;But will God indeed dwell with man on earth? Behold, heaven and the highest heaven cannot contain you; how much less this house that I have built!&rdquo; Solomon&rsquo;s theological question is the central question of the Bible — and the answer is John 1:14: &ldquo;The Word became flesh and dwelt among us.&rdquo; The incarnation is the definitive divine answer to Solomon&rsquo;s wonder. God does indeed dwell with man — not in a stone house but in a human body, in a person, in the community of his people (1 Cor 3:16; Rev 21:3).</p>",
    "19": "<p><em>Type.</em> &ldquo;Yet have regard to the prayer of your servant and to his plea, O YHWH my God.&rdquo; Solomon&rsquo;s intercessory petition for the temple to be the place God hears prayer. Christ&rsquo;s high-priestly prayer in John 17 is the fulfillment of the intercessory pattern — a son praying to the Father on behalf of his people, asking that the Father&rsquo;s glory be revealed in them (17:24). God&rsquo;s &ldquo;ear open to this place&rdquo; is now permanently open toward Christ, through whom all prayer reaches the Father (John 14:13-14).</p>",
    "20": "<p><em>Type.</em> &ldquo;That your eyes may be open day and night toward this house, the place of which you have said, &lsquo;My name shall be there&rsquo;&rdquo; — the name-theology of the temple. The divine name represents the divine character and presence concentrated in one place. Christ is the name above all names (Phil 2:9-11), the one in whose name prayer is offered, healing performed, and salvation received (Acts 4:12). The temple name-presence is fulfilled in Christ as the personal bearer of the divine name — &ldquo;his name is the Word of God&rdquo; (Rev 19:13).</p>",
    "21": "<p><em>Shadow.</em> &ldquo;Hear from heaven your dwelling place, and when you hear, forgive.&rdquo; The temple as the place where forgiveness flows from heaven to earth — the vertical axis of divine-human reconciliation. Christ is the permanent axis of that reconciliation: &ldquo;we have an advocate with the Father, Jesus Christ the righteous&rdquo; (1 John 2:1). Through him, the &ldquo;hear and forgive&rdquo; cycle that Solomon prays for is activated — not temporarily or provisionally but permanently and completely (Heb 10:14).</p>",
    "22": "<p><em>Theme.</em> &ldquo;If a man sins against his neighbor and is made to take an oath.&rdquo; The temple as the place of divine arbitration between sinners — justice flows from the presence of God. Christ is the appointed judge of all humanity (John 5:22, 27; Acts 17:31) who judges with &ldquo;righteous judgment&rdquo; (John 7:24). He knows the heart in a way no human court can (John 2:25), and his final judgment will vindicate the wronged and expose the guilty with perfect precision.</p>",
    "23": "<p><em>Theme.</em> &ldquo;Then hear from heaven and act, and judge your servants.&rdquo; Divine justice as the goal of the temple&rsquo;s mediatorial function. The Day of Judgment that all of Scripture anticipates is the day when Christ renders final verdict (2 Tim 4:8; Rev 20:11-15). But Christ who judges is also Christ who was judged — he underwent the full weight of divine verdict against sin so that those who are &ldquo;in Christ Jesus&rdquo; face no condemnation (Rom 8:1).</p>",
    "24": "<p><em>Theme.</em> &ldquo;If your people Israel are defeated before the enemy because they have sinned against you.&rdquo; Sin leads to defeat; defeat is the covenant consequence. The great defeat of humanity at the hands of sin and death was overcome at the cross. Christ entered the defeat — &ldquo;he was crucified in weakness&rdquo; (2 Cor 13:4) — and turned it into the victory that overflows to his people: &ldquo;thanks be to God who gives us the victory through our Lord Jesus Christ&rdquo; (1 Cor 15:57).</p>",
    "25": "<p><em>Theme.</em> &ldquo;And forgive the sin of your people Israel and bring them again to the land.&rdquo; The restoration prayer — forgiveness followed by return. Christ is both the ground of forgiveness (his blood, Matt 26:28) and the means of return (he is the way, John 14:6). The exile-and-return pattern of Israel&rsquo;s history is the macro-narrative of salvation: humanity exiled from God&rsquo;s presence through sin, returning through the one who is the road back to the Father.</p>",
    "26": "<p><em>Shadow.</em> &ldquo;When heaven is shut up and there is no rain because they have sinned against you.&rdquo; Drought as covenant curse (Deut 11:17; Lev 26:19). Christ is the Living Water who ends the ultimate drought — the spiritual thirst that no rain can quench (John 4:10-14; 7:37-38). He ended the covenant curse of drought by becoming a curse (Gal 3:13), so that &ldquo;the blessing of Abraham might come to the Gentiles&rdquo; — including the blessing of the Spirit poured out like rain (Isa 44:3; Joel 2:28-29).</p>",
    "27": "<p><em>Theme.</em> &ldquo;If they pray toward this place and confess your name and turn from their sin&rdquo; — the three-fold repentance pattern: pray, confess, turn. Christ enables all three: he opens the way for prayer (John 14:13-14), his name is the name confessed for salvation (Rom 10:9-10), and his Spirit produces the turning (Acts 3:19-21; 2 Tim 2:25). He is not only the goal of repentance but its enabler.</p>",
    "28": "<p><em>Theme.</em> &ldquo;If there is famine in the land, if there is pestilence, blight, mildew, locust, or caterpillar&rdquo; — the full catalogue of covenant curses (Deut 28:22-45). Christ bore the full weight of the Deuteronomic curses in his crucifixion, becoming &ldquo;a curse for us&rdquo; (Gal 3:13). Every individual form of disaster in this list ultimately traces to the broken covenant that Christ restored; every category of affliction is answered in the one who is &ldquo;our peace&rdquo; (Eph 2:14) and who &ldquo;makes all things new&rdquo; (Rev 21:5).</p>",
    "29": "<p><em>Theme.</em> &ldquo;Whatever prayer, whatever plea is made by any man or by all your people Israel, each knowing his own affliction and his own sorrow.&rdquo; The individual specificity of prayer — each person knows their own unique wound. Christ, the great high priest, is &ldquo;able to sympathize with our weaknesses, having been tempted in every way as we are&rdquo; (Heb 4:15). He enters into every individual affliction not as a distant deity but as one who has suffered bodily, relationally, and spiritually — he is the high priest for every category of human pain.</p>",
    "30": "<p><em>Revelation of God.</em> &ldquo;You hear from heaven your dwelling place and forgive and render to each whose heart you know.&rdquo; God as the heart-knower (<em>y&omacr;dēaʿ lĕḇāḇôt</em>, Acts 1:24; 15:8). Christ searched and knows hearts (John 2:24-25; Rev 2:23) — a divine attribute applied directly to him. The judgment that renders to each according to their heart (John 5:22) is exercised by the one who became human and therefore knows from the inside what it means to have a human heart.</p>",
    "31": "<p><em>Theme.</em> &ldquo;That they may fear you and walk in your ways all the days that they live.&rdquo; The ultimate goal of all divine discipline and blessing: covenant obedience and fear of YHWH. Christ is both the source of true fear of God (&ldquo;the Spirit of the fear of the LORD&rdquo; resting on him, Isa 11:2) and the one who produces it in his people by the Spirit (Acts 9:31; 2 Cor 7:1). The obedient life that God seeks becomes possible only through union with Christ (Rom 8:3-4).</p>",
    "32": "<p><em>Direct.</em> &ldquo;Likewise when a foreigner, who is not of your people Israel, comes from a far country for the sake of your great name and your mighty hand and your outstretched arm — when he comes and prays toward this house.&rdquo; Jesus cited Isa 56:7 (&ldquo;my house shall be a house of prayer for all peoples&rdquo;) when cleansing the temple (Mark 11:17), directly activating this prayer. Paul applies the same reality in Eph 2:11-22: Gentiles who were &ldquo;far off&rdquo; are brought near in Christ, becoming &ldquo;fellow citizens&rdquo; with Israel in the one household of God. Solomon&rsquo;s foreigner-prayer shadows the Gentile inclusion that Christ enacted.</p>",
    "33": "<p><em>Theme.</em> &ldquo;Hear from heaven your dwelling place and do according to all for which the foreigner calls to you, in order that all peoples of the earth may know your name and fear you.&rdquo; The missional purpose — that all the earth&rsquo;s peoples know the divine name. Christ&rsquo;s Great Commission (Matt 28:18-20) is the concrete mandate for this purpose, and his name is the name proclaimed to all nations (Acts 4:12; Phil 2:9-11). The temple&rsquo;s role as the place where foreigners encounter God becomes the church&rsquo;s role — and the church&rsquo;s power is Christ&rsquo;s name, not a building.</p>",
    "34": "<p><em>Shadow.</em> &ldquo;If your people go out to battle against their enemies, by whatever way you shall send them, and they pray to you toward this city.&rdquo; Prayer toward the temple in time of war — the temple as the axis of divine assistance. Christ is the &ldquo;direction&rdquo; of all prayer: &ldquo;no one comes to the Father except through me&rdquo; (John 14:6). Daniel continued praying toward Jerusalem from exile (Dan 6:10); the early church prayed in the name of Jesus — the new point of orientation for prayer in the new covenant era.</p>",
    "35": "<p><em>Theme.</em> &ldquo;And maintain their cause.&rdquo; The divine advocate-role — YHWH as champion of his people&rsquo;s cause before enemies. Christ is the one in whom God declares the ultimate verdict in his people&rsquo;s favor: &ldquo;If God is for us, who can be against us?&rdquo; (Rom 8:31). The resurrection is the Father&rsquo;s public vindication of Christ&rsquo;s cause — and in Christ, his people&rsquo;s cause is equally vindicated before all accusers (Rom 8:33-34).</p>",
    "36": "<p><em>Direct.</em> &ldquo;There is no one who does not sin.&rdquo; The universal sinfulness declaration — the foundational premise of Solomon&rsquo;s prayer. Paul quotes this universal principle in Rom 3:23 (&ldquo;all have sinned&rdquo;). Christ alone is the exception: &ldquo;in him there is no sin&rdquo; (1 John 3:5; 2 Cor 5:21, &ldquo;he knew no sin&rdquo;). His sinlessness is not a neutral fact but the essential qualification of the one mediator: only the one who does not sin can offer the sinless sacrifice that atones for those who do. Universal sinfulness makes Christ&rsquo;s unique sinlessness necessary and salvifically decisive.</p>",
    "37": "<p><em>Theme.</em> &ldquo;If they take it to heart in the land to which they have been carried captive.&rdquo; The exile-captivity scenario — Israel taken to a foreign land, coming to their senses (the prodigal son pattern of Luke 15:17-18 echoes this exactly). Christ is the one who &ldquo;came to his own&rdquo; (John 1:11) and who, through the Spirit, produces the &ldquo;coming to one&rsquo;s senses&rdquo; in those far from God. The exile is not final; the return is enabled by the one who bore the exile in himself (&ldquo;My God, why have you forsaken me?&rdquo; — the experience of God-abandonment that defines exile).</p>",
    "38": "<p><em>Theme.</em> &ldquo;And they repent and plead with you... saying, &lsquo;We have sinned and have acted perversely and wickedly.&rsquo;&rdquo; The full confession — sin, perversity, wickedness. Christ provided the ground for this confession to be heard: &ldquo;he is faithful and just to forgive our sins and to cleanse us from all unrighteousness&rdquo; (1 John 1:9). The triple acknowledgment (sinned / acted perversely / wickedly) covers every dimension of covenant violation; Christ&rsquo;s atonement is correspondingly comprehensive, covering every dimension of guilt.</p>",
    "39": "<p><em>Theme.</em> &ldquo;Then hear from heaven your dwelling place their prayer and their pleas, and maintain their cause and forgive your people who have sinned against you.&rdquo; The fourfold divine response to prayer from exile: hear, maintain cause, forgive. Christ is the one through whom all four become permanently available. He hears (Heb 5:7), he advocates for our cause (1 John 2:1; Rom 8:34), he forgives (Col 2:13), and as the risen intercessor he &ldquo;always lives to make intercession for&rdquo; those who draw near to God through him (Heb 7:25).</p>",
    "40": "<p><em>Theme.</em> &ldquo;Now, O my God, let your eyes be open and your ears attentive to the prayer of this place.&rdquo; The conclusion-petition — Solomon asks for permanent divine attentiveness to the temple. Christ is the permanent &ldquo;open heaven&rdquo; (John 1:51, the Son of Man on whom angels ascend and descend). His ascension to the right hand of the Father is the eternal opening of the heavenly sanctuary to his people&rsquo;s prayers (Heb 9:24; 10:19-22) — not a building that God watches but a person who is always before the Father on our behalf.</p>",
    "41": "<p><em>Direct.</em> &ldquo;Now therefore arise, O YHWH God, and go to your resting place, you and the ark of your might.&rdquo; Quoting Ps 132:8. The ark of might is the symbol of YHWH&rsquo;s powerful presence; the resting place is the temple. Christ is both the ark and the resting place: he is &ldquo;the power of God&rdquo; (1 Cor 1:24) and &ldquo;our rest&rdquo; (Heb 4:9-11). The Sabbath rest that Ps 132 envisions as YHWH&rsquo;s own rest in the temple is fulfilled in Christ who offers rest to all who labor and are heavy-laden (Matt 11:28-29).</p>",
    "42": "<p><em>Direct.</em> &ldquo;O YHWH God, do not turn away the face of your anointed one. Remember your steadfast love for David your servant.&rdquo; The final word of Solomon&rsquo;s prayer is a plea for the <em>māšîaḥ</em> — the anointed one. It is the only verse in Chronicles where a king prays explicitly for YHWH&rsquo;s anointed. The Father&rsquo;s answer is the resurrection: he did not turn away the face of his anointed but vindicated him, &ldquo;highly exalted him and bestowed on him the name above all names&rdquo; (Phil 2:9). The steadfast love (<em>ḥăsādîm</em>) promised to David is given to all who are in David&rsquo;s greater Son (Acts 13:34, citing Isa 55:3: &ldquo;the holy and sure blessings of David&rdquo;).</p>"
  },
  "7": {
    "1": "<p><em>Shadow / Type.</em> Fire from heaven descends and consumes the burnt offering — the divine acceptance of Solomon&rsquo;s sacrifice confirmed by supernatural fire, exactly as when Aaron&rsquo;s first sacrifice was accepted (Lev 9:24). The fire is the Father&rsquo;s &ldquo;yes&rdquo; to the offering. At the cross, the Father accepted Christ&rsquo;s self-offering — the resurrection is the divine fire of vindication that consumed and transformed what was offered. At Pentecost, &ldquo;tongues as of fire&rdquo; (Acts 2:3) rest on the believers who are the new temple, signaling that the Spirit-fire of divine acceptance now dwells in them rather than on an altar.</p>",
    "2": "<p><em>Shadow.</em> The priests cannot enter the house because the glory of YHWH fills it — the overwhelming presence excludes even the dedicated ministers. Contrast with the new covenant: &ldquo;Therefore brothers, since we have confidence to enter the holy places by the blood of Jesus... let us draw near&rdquo; (Heb 10:19-22). The glory that excluded the priests from Solomon&rsquo;s temple now, through Christ&rsquo;s blood, becomes the glory that welcomes every believer into the divine presence. The exclusion of 7:2 is answered by the invitation of Heb 10:22.</p>",
    "3": "<p><em>Theme.</em> All Israel bows face to the pavement and worships — the prostrate posture of creatures before the Creator, spontaneously enacted when the divine glory falls. In Revelation, the elders and living creatures prostrate themselves before the Lamb &ldquo;slain from the foundation of the world&rdquo; (Rev 5:6-14) — the same posture now directed toward Christ as the worthy one who purchased people for God with his blood. The &ldquo;his steadfast love endures forever&rdquo; refrain (Ps 136) becomes in Rev 5:9 the new song of the redeemed from every tribe and tongue and people.</p>",
    "4": "<p><em>Shadow.</em> The king and all the people offer sacrifices before YHWH. The repeated offerings of the Solomonic era — countless animals across the temple&rsquo;s history — attest that the sacrificial system pointed beyond itself. Hebrews 10:1-4 states the logic directly: &ldquo;it is impossible for the blood of bulls and goats to take away sins.&rdquo; Every animal offered at Solomon&rsquo;s altar was a promissory note pointing to the one perfect offering that would actually accomplish what the system shadowed.</p>",
    "5": "<p><em>Shadow.</em> Twenty-two thousand bulls and one hundred twenty thousand sheep — the enormous scale of Solomon&rsquo;s dedication offering. The very scale signals the inadequacy of animal blood: no quantity of animals can exhaust the requirement. Hebrews 10:10-14 resolves the insufficiency: &ldquo;by a single offering he has perfected for all time those who are being sanctified.&rdquo; Where Solomon needed thousands upon thousands, Christ needed only once — and once was infinitely sufficient.</p>",
    "6": "<p><em>Theme.</em> The priests and Levites with musical instruments praising YHWH &ldquo;for his steadfast love endures forever&rdquo; — the refrain from Pss 118 and 136. Christ&rsquo;s resurrection is the ultimate demonstration that &ldquo;his steadfast love endures forever&rdquo; — his love could not be extinguished by death or held by the grave. The eternal worship of the redeemed (Rev 5:9-14; 15:3-4) fulfills this liturgical pattern; the &ldquo;new song&rdquo; they sing has the same theme — the unfailing covenant love of God, now revealed most fully in the Lamb.</p>",
    "7": "<p><em>Shadow.</em> Solomon consecrates the middle of the court as an altar space because the bronze altar was too small for the burnt offerings. The existing structure was insufficient for the scale of what was offered. This shadows the cross: the entire temple complex with all its altars was insufficient for the weight of human sin. The true offering required something beyond all temple altars — &ldquo;he suffered outside the gate in order to sanctify the people through his own blood&rdquo; (Heb 13:12), outside the sacred precincts, on a different kind of altar altogether.</p>",
    "8": "<p><em>Shadow.</em> The feast of seven days followed by another seven days — the Feast of Tabernacles combined with the temple dedication. The Feast of Tabernacles was the great harvest festival celebrating YHWH&rsquo;s provision in the wilderness and the ingathering of the harvest. John 7:37-39 places Jesus&rsquo; &ldquo;rivers of living water&rdquo; declaration at the climax of the Feast of Tabernacles, directly claiming to be the fulfillment of what the feast anticipated. Christ is the ultimate tabernacle — &ldquo;the Word became flesh and tabernacled (<em>ĕsk&emacr;nōsen</em>) among us&rdquo; (John 1:14).</p>",
    "9": "<p><em>Shadow.</em> The eighth day — the solemn assembly after the seven days of feasting. The eighth day of the tabernacles celebration carries eschatological significance: after the seven-day week of this age comes the eighth day, the day of new creation. The resurrection of Jesus happened on the first day of the week — also the &ldquo;eighth day&rdquo; after the previous week — inaugurating the new creation. The &ldquo;solemn assembly&rdquo; (<em>ʿăṣeret</em>) of the eighth day prefigures the gathered assembly of the redeemed in the age to come.</p>",
    "10": "<p><em>Theme.</em> The people returned home joyful and glad of heart for the good that YHWH had done for David and Solomon and Israel his people. The joy of completion — the temple is built, the glory has fallen, the offerings are accepted. The fuller joy is the &ldquo;joy set before Christ&rdquo; for which he endured the cross (Heb 12:2), and the joy of his people who receive &ldquo;an inheritance that is imperishable, undefiled, and unfading&rdquo; (1 Pet 1:4) — a joy that flows from a work more final than Solomon&rsquo;s.</p>",
    "11": "<p><em>Type.</em> &ldquo;Thus Solomon finished the house of YHWH and the king&rsquo;s own house.&rdquo; The completion of both the sacred and the royal project in one reign. Christ&rsquo;s &ldquo;It is finished&rdquo; (John 19:30, <em>tetelestai</em>) is the definitive completion — the work of salvation, the true temple-building project, accomplished once for all. Solomon&rsquo;s completion was provisional (the temple would be destroyed in 586 BCE); Christ&rsquo;s completion is eternal and indestructible.</p>",
    "12": "<p><em>Theme.</em> &ldquo;I have heard your prayer and have chosen this place for myself as a house of sacrifice.&rdquo; The Father&rsquo;s answer to prayer: heard and chosen. The Father&rsquo;s answer to Christ&rsquo;s prayer (John 11:42, &ldquo;Father, I thank you that you have heard me&rdquo;; John 17:24, &ldquo;Father, I desire that they also... may be with me where I am&rdquo;) is the resurrection and the glorification — the Father always hears the Son. This verse assures every petitioner that the God who heard Solomon hears Christ, and through Christ hears his people.</p>",
    "13": "<p><em>Theme.</em> &ldquo;When I shut up the heavens so that there is no rain, or command the locust to devour the land, or send pestilence among my people&rdquo; — divine sovereignty over natural disaster. Christ who stilled the storm (Mark 4:39), healed the sick (Mark 1:34), and cast out demons (Mark 1:34) demonstrated in his ministry that the sovereign Lord of creation had entered creation to reverse curse. His resurrection is the beginning of the reversal of the entire order of decay and death (Rom 8:21-22).</p>",
    "14": "<p><em>Theme.</em> &ldquo;If my people who are called by my name humble themselves, and pray and seek my face and turn from their wicked ways, then I will hear from heaven and will forgive their sin and heal their land.&rdquo; The great conditional promise. Christ fulfills every condition on behalf of his people: he humbled himself to the point of death on a cross (Phil 2:8), he prays perfectly (Heb 7:25), he sought the Father&rsquo;s face (John 17), he is the one without sin who turned entirely from wickedness (2 Cor 5:21). In Christ, all conditions are perfectly met — the healing of the land (Rom 8:21; Rev 21:5) flows from his completed obedience (2 Cor 1:20).</p>",
    "15": "<p><em>Theme.</em> &ldquo;Now my eyes will be open and my ears attentive to the prayer offered in this place.&rdquo; The permanent divine attentiveness to the temple. Christ is the permanent open heaven: his ascension inaugurated the continuous intercession that keeps the heavenly sanctuary open to his people (Heb 7:25; 9:24). &ldquo;The eyes of the Lord are toward the righteous and his ears toward their cry&rdquo; (Ps 34:15; 1 Pet 3:12) — permanently true for those who are righteous in Christ.</p>",
    "16": "<p><em>Theme.</em> &ldquo;I have chosen and consecrated this house that my name may be there forever. My eyes and my heart will be there for all time.&rdquo; The divine consecration of the temple as permanent — God&rsquo;s name, eyes, and heart pledged to it. Christ is the one on whom the divine name is permanently placed (Rev 3:12; 14:1), and the one to whom the Father&rsquo;s heart is permanently turned (&ldquo;You are my beloved Son, with whom I am well pleased,&rdquo; Matt 3:17). His people, named with his name, inherit this divine attention — &ldquo;the Lord knows those who are his&rdquo; (2 Tim 2:19).</p>",
    "17": "<p><em>Theme.</em> &ldquo;And as for you, if you walk before me as David your father walked&hellip;&rdquo; — the conditional covenant: perfect obedience required. Christ is the one person in all of history who perfectly walked before God — &ldquo;I always do what pleases the Father&rdquo; (John 8:29). Where Solomon and every subsequent son of David failed this condition, Christ fulfills it perfectly, securing the covenant promises not through conditional human obedience that might fail but through his own perfect and permanent obedience (Rom 5:19).</p>",
    "18": "<p><em>Direct.</em> &ldquo;There shall not fail you a man to sit on the throne of Israel.&rdquo; Acts 2:30-31 applies this directly to Christ: David &ldquo;being therefore a prophet&hellip; he foresaw and spoke about the resurrection of the Christ.&rdquo; Acts 13:34 adds: &ldquo;that he raised him from the dead, no more to return to corruption, he has spoken in this way: &lsquo;I will give you the holy and sure blessings of David.&rsquo;&rdquo; The resurrection guarantees that the Davidic throne is permanently and indestructibly occupied — Christ reigns and cannot be dethroned.</p>",
    "19": "<p><em>Shadow.</em> &ldquo;But if you turn aside and forsake my statutes and my commandments that I have set before you.&rdquo; The conditional curse — faithlessness leads to exile and disgrace. This threat was literally fulfilled in 586 BCE. But Christ underwent the fulfilment of the covenant curses in his own person: he was &ldquo;cut off from the land of the living&rdquo; (Isa 53:8), abandoned, cast out of the holy city, crucified outside the gate (Heb 13:12). He absorbed the curse-of-exile so that his people would receive the blessing-of-return.</p>",
    "20": "<p><em>Shadow.</em> &ldquo;Then I will pluck them up from my land that I have given them&rdquo; — the ultimate covenant threat: removal from the land. Christ was &ldquo;plucked up&rdquo; — taken from among the living — so that his people would never be permanently removed from God&rsquo;s presence. His promise stands: &ldquo;I will never leave you nor forsake you&rdquo; (Heb 13:5); &ldquo;no one will snatch them out of my hand&rdquo; (John 10:28). The covenant exile that Solomon&rsquo;s warning threatened is answered by the one who went into exile in their place.</p>",
    "21": "<p><em>Shadow.</em> &ldquo;And this house, which was exalted, everyone passing by will be astonished and say, &lsquo;Why has YHWH done this?&rsquo;&rdquo; The desolated temple becomes an object lesson for the nations. The cross is the greater desolation that becomes the greater object lesson: Christ hanging outside the city gate, the one through whom all things were made, destroyed in a public spectacle. The answer to &ldquo;Why has God done this?&rdquo; is 2 Cor 5:21: &ldquo;For our sake he made him to be sin who knew no sin.&rdquo; The desolation of the Lamb answers the desolation of the temple.</p>",
    "22": "<p><em>Theme.</em> &ldquo;Because they abandoned YHWH the God of their fathers who brought them out of Egypt, and laid hold on other gods and worshipped them and served them.&rdquo; The covenant apostasy verdict — the explanation for ruin. Christ was abandoned (&ldquo;My God, my God, why have you forsaken me?&rdquo; — Matt 27:46) not for his own apostasy (he had none) but for ours. He entered the place of God-abandonment that covenant sin produces, so that we who had abandoned God might be received back. The terminus of the covenant curse is the cross; the terminus of the curse on the cross is the resurrection.</p>"
  },
  "8": {
    "1": "<p><em>Theme.</em> After twenty years of building — the house of YHWH and his own house — Solomon turns to the cities Hiram had given back. The completion of the temple project marks a transition: from concentrated building to expansive reign. Christ, having completed the work of salvation (&ldquo;It is finished&rdquo;), now reigns and extends his kingdom through the proclamation of the gospel. The post-completion expansion of Solomon&rsquo;s realm shadows the post-resurrection expansion of Christ&rsquo;s kingdom through the church (Acts 1:8).</p>",
    "2": "<p><em>Theme.</em> Solomon resettled the cities Hiram returned and put the people of Israel in them — the repopulation of returned cities. The returning of what was given as partial payment and its repopulation with God&rsquo;s people prefigures the reclamation of the nations for God: what was &ldquo;given&rdquo; in the Fall is reclaimed and repopulated with the people of the new covenant (2 Cor 5:19, &ldquo;God was in Christ reconciling the world to himself&rdquo;).</p>",
    "3": "<p><em>Theme.</em> Solomon went to Hamath-zobah and took it — military conquest expanding the Solomonic realm to its Davidic maximum. The promise of Ps 2:8 (&ldquo;ask of me, and I will make the nations your heritage&rdquo;) is what Solomon partially fulfills. Christ receives this inheritance fully: &ldquo;All authority in heaven and on earth has been given to me&rdquo; (Matt 28:18), and his kingdom expands not through military force but through the Spirit-empowered proclamation of the gospel (Rom 15:19-20).</p>",
    "4": "<p><em>Theme.</em> Solomon built Tadmor (Palmyra) in the wilderness and storage cities in Hamath — establishing infrastructure in distant territories. Christ builds his church in the &ldquo;wilderness&rdquo; of the nations, establishing communities of the redeemed in places far from Jerusalem. The storage cities that provision the kingdom correspond to the local churches that store and distribute the spiritual resources of Christ&rsquo;s kingdom (Eph 4:11-16).</p>",
    "5": "<p><em>Theme.</em> Solomon built Upper and Lower Beth-horon as fortified cities — securing the strategic passes into the land. Christ secures the entry into the eternal city: &ldquo;I am the door; if anyone enters through me he will be saved&rdquo; (John 10:9). The fortified approaches that prevented enemy penetration prefigure Christ&rsquo;s promise that &ldquo;the gates of Hades will not prevail&rdquo; against his church (Matt 16:18). He both provides access (the door) and prevents enemy access (the fortified gate).</p>",
    "6": "<p><em>Theme.</em> Baalath, all of Solomon&rsquo;s storage cities, chariot cities, cavalry cities — the infrastructure of the greatest earthly kingdom. In Christ &ldquo;all the fullness of God was pleased to dwell&rdquo; (Col 1:19) and &ldquo;in him are hidden all the treasures of wisdom and knowledge&rdquo; (Col 2:3). The storehouses and supply systems of Solomon&rsquo;s empire are a shadow of the inexhaustible resources of Christ&rsquo;s kingdom — &ldquo;the riches of his grace, which he lavished upon us&rdquo; (Eph 1:7-8).</p>",
    "7": "<p><em>Shadow.</em> The non-Israelite peoples remaining in the land — Hittites, Amorites, Perizzites, Hivites, Jebusites — not destroyed but made into forced laborers. The survival of Canaanite peoples within Solomon&rsquo;s kingdom and their service to it prefigures the Gentile inclusion in God&rsquo;s people. Those who were once enemies of Israel (Eph 2:12, &ldquo;alienated from the commonwealth of Israel&rdquo;) are incorporated into the household of God through Christ. Former opponents become &ldquo;fellow heirs, members of the same body, and partakers of the promise in Christ Jesus&rdquo; (Eph 3:6).</p>",
    "8": "<p><em>Shadow.</em> The descendants of those peoples whom Israel had not destroyed were made into a levy of forced workers — a status that continued to the time of the Chronicler. The nations serving the Davidic king is the shadow of the nations serving the greater David. But the labor is transformed: not compelled service to a human empire but willing worship to the risen King (&ldquo;every knee will bow&rdquo; — Phil 2:10-11), motivated not by military subjugation but by the gospel of redeeming love.</p>",
    "9": "<p><em>Shadow.</em> &ldquo;But of the people of Israel Solomon made no slaves for his work; they were soldiers, commanders of his officers, and commanders of his chariots and cavalry.&rdquo; Israel serves as leaders and warriors, not as laborers. The people of God under the new covenant are described as &ldquo;a royal priesthood&rdquo; (1 Pet 2:9) and &ldquo;priests and kings&rdquo; (Rev 1:6; 5:10) — not slaves but sons, not servants of the earthly machinery but participants in the royal and priestly governance of the new creation. Christ frees his people from slavery to make them co-heirs of the kingdom (Gal 4:7; Rom 8:17).</p>",
    "10": "<p><em>Shadow.</em> The 250 chief officers who exercised authority over the people under Solomon — the administrative hierarchy of the kingdom. Christ appoints his own officers for the governance of his kingdom: apostles, prophets, evangelists, pastors, and teachers (Eph 4:11), given &ldquo;to equip the saints for the work of ministry&rdquo;. The twelve apostles will sit on twelve thrones judging the twelve tribes of Israel in the age to come (Matt 19:28) — the administrative pattern of Solomon&rsquo;s kingdom fulfilled in an eternal judicial-governing role.</p>",
    "11": "<p><em>Theme.</em> Solomon moved Pharaoh&rsquo;s daughter from the City of David to the house he built for her, because &ldquo;the places are holy where the ark of YHWH has come.&rdquo; The maintenance of holiness boundaries — not excluding the Egyptian princess from the kingdom, but distinguishing what belongs to the holy precincts. Christ maintains the holy character of the new Jerusalem: &ldquo;nothing unclean will ever enter it, nor anyone who does what is detestable or false, but only those who are written in the Lamb&rsquo;s book of life&rdquo; (Rev 21:27). Holiness is not the rejection of the Gentile but the transformation required to dwell in the divine presence.</p>",
    "12": "<p><em>Shadow.</em> Solomon offered burnt offerings on the altar — daily, Sabbath, new moon, and festival offerings. The regular rhythm of Solomonic sacrifice points beyond itself. Christ fulfilled the entire sacrificial calendar: he is the Passover Lamb (1 Cor 5:7), the firstfruits of the resurrection (1 Cor 15:20-23, at the Feast of Firstfruits), and the source of the Spirit poured out at Pentecost (Acts 2). The &ldquo;daily&rdquo; rhythm of sacrifice anticipates the once-for-all sacrifice that makes all further repetition unnecessary (Heb 10:10).</p>",
    "13": "<p><em>Shadow.</em> The three annual feasts — Unleavened Bread (Passover), Weeks (Pentecost), and Tabernacles — the complete cycle of Israel&rsquo;s festival calendar. Paul writes that these festivals are &ldquo;a shadow of the things to come, but the substance belongs to Christ&rdquo; (Col 2:16-17). Christ is the reality that each feast was designed to anticipate: the Passover Lamb, the firstfruits of the Spirit (Pentecost), and the final harvest-ingathering of all nations (Tabernacles/Rev 7:9). The entire festival calendar is a curriculum in Christ.</p>",
    "14": "<p><em>Shadow.</em> &ldquo;He appointed the divisions of the priests for their service, and the Levites for their posts of praise and ministry before the priests as the duty of each day required.&rdquo; The carefully maintained Davidic order — priests and Levites in their assignments, functioning without deviation. Hebrews applies the priestly pattern to Christ: he is the great high priest in the order of Melchizedek (Heb 7:11-17) whose priesthood is &ldquo;inviolable because he continues forever&rdquo; (Heb 7:24). The organized priestly service that Solomon maintained points to the eternal, unchanging priestly ministry of Christ.</p>",
    "15": "<p><em>Theme.</em> &ldquo;They did not deviate from the king&rsquo;s commandment to the priests and Levites in any matter, or in the matter of the treasuries.&rdquo; Perfect obedience to royal command — the Solomonic organization executed without deviation. Christ&rsquo;s servants under the new covenant are called to similar faithfulness: &ldquo;it is required of stewards that they be found faithful&rdquo; (1 Cor 4:2). But more fundamentally, Christ himself is the servant who deviated from God&rsquo;s command in nothing: &ldquo;he was obedient to the point of death, even death on a cross&rdquo; (Phil 2:8) — the perfect execution of the Father&rsquo;s royal command.</p>",
    "16": "<p><em>Theme.</em> &ldquo;Thus was accomplished all the work of Solomon from the day the foundation was laid until it was finished. So the house of YHWH was completed.&rdquo; The completion summary — foundation to finish. Christ is both the foundation (&ldquo;no one can lay a foundation other than the one that is laid, which is Jesus Christ,&rdquo; 1 Cor 3:11) and the one who brings the work to completion. His &ldquo;It is finished&rdquo; (John 19:30) corresponds to this verse&rsquo;s completed-work summary: what Solomon completed in stone and cedar, Christ completed in flesh and blood, and the completion is eternal.</p>",
    "17": "<p><em>Theme.</em> Solomon went to Ezion-geber and Eloth on the Red Sea — the southernmost reach of his commercial network, the gateway to the Indian Ocean trade routes. The expansion to the sea&rsquo;s edge shadows the missional reach of the gospel to &ldquo;the ends of the earth&rdquo; (Acts 1:8; Isa 49:6). Solomon&rsquo;s trading missions that bring the wealth of distant peoples to Jerusalem prefigure the gathering of all peoples into the new Jerusalem, &ldquo;the kings of the earth bringing their glory and honor into it&rdquo; (Rev 21:24-26).</p>",
    "18": "<p><em>Shadow.</em> Hiram sends Solomon ships and experienced sailors; they bring 450 talents of gold from Ophir. The nations&rsquo; wealth flowing to Solomon&rsquo;s kingdom is the shadow of the eschatological ingathering prophesied in Ps 72:10-11 (&ldquo;May the kings of Tarshish and of the coastlands render him tribute&rdquo;) and Rev 21:24-26 (&ldquo;the kings of the earth will bring their glory into&rdquo; the New Jerusalem). Solomon&rsquo;s Ophir gold is a foretaste of the nations&rsquo; ultimate tribute to the greater Solomon — not a commodity trade but a worship-rendering by all creation to the Lamb who sits on the eternal throne.</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', '2chronicles')
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, CHRON2_CHRIST_6_8)
    after = sum(len(v) for v in existing.values())
    save_comm('mkt-christ', '2chronicles', existing)
    print(f'2chronicles mkt-christ ch 6-8: wrote {after - before} verses')

if __name__ == '__main__':
    main()
